const chatBox = document.getElementById("chatBox");
const input = document.getElementById("userInput");
const sendBtn = document.getElementById("sendBtn");

function addMessage(text, type = "bot") {
  const msg = document.createElement("div");
  msg.classList.add("message", type);
  msg.innerText = text;
  chatBox.appendChild(msg);
  chatBox.scrollTop = chatBox.scrollHeight;
}

sendBtn.addEventListener("click", handleSend);
input.addEventListener("keypress", (e) => {
  if (e.key === "Enter") handleSend();
});

function handleSend() {
  const text = input.value.trim();
  if (!text) return;

  addMessage(text, "user");
  input.value = "";

  setTimeout(() => {
    botReply(text.toLowerCase());
  }, 700);
}

function botReply(text) {
  let reply = "";

  if (text.includes("hello") || text.includes("hi")) {
    reply = "Hey 💜 I’m here with you. How are you feeling right now?";
  } 
  else if (text.includes("sad") || text.includes("low")) {
    reply = "I’m really sorry you’re feeling this way 💔 Want to tell me what’s making it heavy?";
  } 
  else if (text.includes("tired") || text.includes("drained") || text.includes("exhausted")) {
    reply = "That sounds really draining 😔 You’ve been carrying a lot, haven’t you?";
  } 
  else if (text.includes("lonely")) {
    reply = "Feeling lonely hurts a lot 💜 But you’re not alone here. I’m listening.";
  } 
  else if (text.includes("stress") || text.includes("pressure")) {
    reply = "Stress can feel overwhelming 😞 Do you want to talk about what’s causing it?";
  } 
  else {
    reply = "I’m here with you 💜 Take your time. Tell me more.";
  }

  addMessage(reply, "bot");
}
